```class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        vector<int> result;
        int n = num.length();
        int a = 0, b = 1, c;
        for (int i = 0; i < n; i++) {
            if (isdigit(num[i])) {
                c = num[i] - '0';
                result.push_back(c);
                a = a * 10 + c;
                b = b * 10 + c;
            }
        }
        return result;
    }
};
```

